import{_ as s,o as t,c as a,a0 as i}from"./chunks/framework.jwovEGr5.js";const c=JSON.parse('{"title":"Handle Subscription Requests","description":"","frontmatter":{},"headers":[],"relativePath":"admin/subscription-requests.md","filePath":"admin/subscription-requests.md"}'),n={name:"admin/subscription-requests.md"};function l(o,e,r,p,u,h){return t(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="handle-subscription-requests" tabindex="-1">Handle Subscription Requests <a class="header-anchor" href="#handle-subscription-requests" aria-label="Permalink to &quot;Handle Subscription Requests&quot;">​</a></h1><p>This guide is for <code>Supreme Admin</code> users only.</p><p>The <strong>Subscription Requests</strong> page is the admin-side queue for manual subscription, upgrade, quota, and premium-interest requests.</p><blockquote><p>Screenshot placeholder: <code>subs-admin-requests.png</code> (S67)</p></blockquote><h2 id="what-you-can-do-here" tabindex="-1">What you can do here <a class="header-anchor" href="#what-you-can-do-here" aria-label="Permalink to &quot;What you can do here&quot;">​</a></h2><p>From this queue, you can:</p><ul><li>filter by status</li><li>filter by request type</li><li>open request details</li><li>add an admin note</li><li>send payment instructions</li><li>send a reply</li><li>approve, reject, or complete the request</li><li>optionally assign a plan when completing</li></ul><h2 id="admin-side-request-flow" tabindex="-1">Admin-side request flow <a class="header-anchor" href="#admin-side-request-flow" aria-label="Permalink to &quot;Admin-side request flow&quot;">​</a></h2><p>This is the core state machine for the admin side:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;pending&quot;] --&gt; B[&quot;approve&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; C[&quot;reject&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; D[&quot;send payment instructions&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[&quot;awaiting_payment&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[&quot;reply&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; G[&quot;complete&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; H[&quot;reject&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; I[&quot;approved&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I --&gt; G</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; J[&quot;completed&quot;]</span></span></code></pre></div><p>This complements the requester-side explanation in <a href="./../subscriptions/payment-instructions.html">Payment Instructions &amp; Completing a Request</a>.</p><h2 id="what-the-detail-panel-includes" tabindex="-1">What the detail panel includes <a class="header-anchor" href="#what-the-detail-panel-includes" aria-label="Permalink to &quot;What the detail panel includes&quot;">​</a></h2><p>The request detail view can show:</p><ul><li>requester</li><li>subject</li><li>requested plan</li><li>request type</li><li>preferred contact</li><li>requester message</li><li>requested quota or metadata</li><li>payment instructions</li><li>conversation history</li><li>admin note</li></ul><p>It also lets you choose an optional plan to assign when the request is completed.</p><h2 id="good-practice" tabindex="-1">Good practice <a class="header-anchor" href="#good-practice" aria-label="Permalink to &quot;Good practice&quot;">​</a></h2><ul><li>Use <strong>reply</strong> for clarifications without changing the request state.</li><li>Use <strong>payment instructions</strong> when the next step is manual payment outside the app.</li><li>Use <strong>complete</strong> only when the subscription change is truly ready to take effect.</li><li>Use <strong>assign plan on completion</strong> carefully so the final state matches what was agreed.</li></ul>`,17)])])}const q=s(n,[["render",l]]);export{c as __pageData,q as default};
